import { Decoration } from '@codemirror/view';
import clsx from 'clsx';

import * as styles from '../FilterField.sty.js';

/** @internal */
export const statementMark = Decoration.mark({
  inclusive: true,
  class: styles.filterStatement,
  tagName: 'span',
});

/** @internal */
export const incompleteStatementMark = Decoration.mark({
  inclusive: true,
  class: styles.incompleteFilterStatement,
  tagName: 'span',
});

/** @internal */
export const intermediateStatementMark = Decoration.mark({
  inclusive: true,
  class: styles.intermediateFilterStatement,
  tagName: 'span',
});

/** @internal */
export const pastingMark = Decoration.mark({
  inclusive: true,
  class: styles.pastedContent,
  tagName: 'span',
});

/** @internal */
export const existsMark = Decoration.mark({
  inclusive: true,
  class: styles.existsOperator,
  tagName: 'span',
});

/** @internal */
export const searchMark = Decoration.mark({
  inclusive: true,
  class: styles.operator,
  tagName: 'span',
});

/** @internal */
export const keyMark = Decoration.mark({
  inclusive: true,
  class: styles.filterKey,
  tagName: 'span',
});

/** @internal */
export const valueMark = Decoration.mark({
  inclusive: true,
  class: styles.filterValue,
  tagName: 'span',
});

/** @internal */
export const variableMark = Decoration.mark({
  inclusive: true,
  class: styles.variable,
  tagName: 'span',
});

/** @internal */
export const escapedCharacterMark = Decoration.mark({
  inclusive: true,
  class: styles.escapedCharacter,
  tagName: 'span',
});

/** @internal */
export const errorMark = Decoration.mark({
  inclusive: true,
  class: styles.error,
  tagName: 'span',
});

// The error indicator for spot errors is shifted to either before or after
// the error's position. The actual error covers a slightly bigger range to have
// a bigger hover area for showing the tooltip.
/**
 * @internal
 */
export const preSpotErrorMark = Decoration.mark({
  inclusive: true,
  class: clsx(styles.spotError, styles.preSpotError),
  tagName: 'span',
});

/** @internal */
export const postSpotErrorMark = Decoration.mark({
  inclusive: true,
  class: clsx(styles.spotError, styles.postSpotError),
  tagName: 'span',
});
